const fs = require('fs');
const path = require('path');

const brainDir = path.join(__dirname, '..', '..', 'agency-brain');
const destFile = path.join(__dirname, '..', 'src', 'data', 'brainDocs.ts');

function getFilesRecursively(dir, rootDir = dir) {
  let results = [];
  const list = fs.readdirSync(dir);
  list.forEach(file => {
    const fullPath = path.join(dir, file);
    const stat = fs.statSync(fullPath);
    if (stat && stat.isDirectory()) {
      results = results.concat(getFilesRecursively(fullPath, rootDir));
    } else if (file.endsWith('.md')) {
      const relPath = path.relative(rootDir, fullPath).replace(/\\/g, '/');
      results.push({
        path: relPath,
        absPath: fullPath
      });
    }
  });
  return results;
}

// Simple but robust CSV parser to handle quoted strings
function parseCSV(filePath) {
  if (!fs.existsSync(filePath)) return [];
  const content = fs.readFileSync(filePath, 'utf8');
  const lines = content.split('\n').map(l => l.trim()).filter(l => l !== '');
  if (lines.length === 0) return [];

  const headers = parseCSVLine(lines[0]);
  const data = [];

  for (let i = 1; i < lines.length; i++) {
    const values = parseCSVLine(lines[i]);
    const obj = {};
    headers.forEach((h, idx) => {
      obj[h] = values[idx] || '';
    });
    data.push(obj);
  }
  return data;
}

function parseCSVLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];
    if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ',' && !inQuotes) {
      result.push(current.trim());
      current = '';
    } else {
      current += char;
    }
  }
  result.push(current.trim());
  return result;
}

if (!fs.existsSync(brainDir)) {
  console.error(`Agency brain directory not found at: ${brainDir}`);
  process.exit(1);
}

// Bundle MD Files
const mdFiles = getFilesRecursively(brainDir);
const docsData = {};

mdFiles.forEach(file => {
  const content = fs.readFileSync(file.absPath, 'utf8');
  docsData[file.path] = content;
});

// Parse Watchdog logs and Healthcare Leads
const watchdogCSVPath = path.join(brainDir, 'operations', 'watchdog_log.csv');
const leadsCSVPath = path.join(brainDir, 'clients', 'healthcare_leads.csv');

const watchdogLogs = parseCSV(watchdogCSVPath);
const healthcareLeads = parseCSV(leadsCSVPath);

const tsContent = `// Automatically generated by bundle-brain.js
export interface BrainDocs {
  [path: string]: string;
}

export const brainDocs: BrainDocs = ${JSON.stringify(docsData, null, 2)};

export interface WatchdogLog {
  timestamp: string;
  agent_id: string;
  action_type: string;
  description: string;
  status: string;
  output_file: string;
}

export const watchdogLogs: any[] = ${JSON.stringify(watchdogLogs, null, 2)};

export interface HealthcareLead {
  Organization: string;
  Signal_Role: string;
  Location: string;
  Primary_EHR: string;
  Primary_EHR_Placeholder: string;
  Hiring_Density: string;
  Qualification_Score: string;
  Denial_Signals: string;
  Job_Link: string;
  Detected_At: string;
  Status: string;
  Decision_Maker: string;
  Apollo_Contact: string;
  Email: string;
  LinkedIn_Profile: string;
  enriched: string;
}

export const healthcareLeads: any[] = ${JSON.stringify(healthcareLeads, null, 2)};
`;

const destDir = path.dirname(destFile);
if (!fs.existsSync(destDir)) {
  fs.mkdirSync(destDir, { recursive: true });
}

fs.writeFileSync(destFile, tsContent, 'utf8');
console.log(`Bundled MDs, parsed watchdog logs (${watchdogLogs.length}), parsed leads (${healthcareLeads.length}) into ${destFile}`);
